const totalTasks = Number($env.TOTAL_TASKS || 1000);
const batchSize = Number($env.BATCH_SIZE || 10);

if (!Number.isInteger(totalTasks) || totalTasks <= 0) {
  throw new Error("TOTAL_TASKS must be a positive integer");
}

if (!Number.isInteger(batchSize) || batchSize <= 0) {
  throw new Error("BATCH_SIZE must be a positive integer");
}

const batchCount = Math.ceil(totalTasks / batchSize);
const batches = [];

for (let i = 1; i <= batchCount; i++) {
  const remaining = totalTasks - (i - 1) * batchSize;
  batches.push({
    json: {
      batchNumber: i,
      batchSize: Math.min(batchSize, remaining),
      totalTasks,
      batchCount
    }
  });
}

return batches;

