const items = $input.all();

function normalizeDate(value) {
  if (!value) return null;
  const s = String(value).trim();

  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;

  const m = s.match(/^(\d{4}-\d{2}-\d{2})/);
  if (m) return m[1];

  return null;
}

function tryParseObject(text) {
  try {
    return JSON.parse(text);
  } catch (_) {
    try {
      const fixed = text
        .replace(/([{,]\s*)([A-Za-z_][A-Za-z0-9_]*)(\s*:)/g, '$1"$2"$3')
        .replace(/,(\s*})/g, '$1');

      return JSON.parse(fixed);
    } catch (_) {
      return null;
    }
  }
}

const output = [];

for (const [index, item] of items.entries()) {
  const raw = String(item.json.response || "").trim();

  if (!raw) {
    output.push({
      json: {
        batchIndex: index,
        batchCount: 0,
        batchError: "Empty Ollama response",
        tasks: []
      }
    });
    continue;
  }

  let text = raw
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const matches = text.match(/\{[^{}]*\}/g);

  if (!matches || matches.length === 0) {
    output.push({
      json: {
        batchIndex: index,
        batchCount: 0,
        batchError: "No object-like records found",
        tasks: []
      }
    });
    continue;
  }

  const tasks = [];

  for (const m of matches) {
    const task = tryParseObject(m);
    if (!task) continue;

    const cleaned = {
      title: String(task.title || "").trim(),
      description: String(task.description || task.title || "Generated task").trim(),
      status: String(task.status || "").trim().toUpperCase(),
      priority: String(task.priority || "").trim().toUpperCase(),
      dueDate: normalizeDate(task.dueDate)
    };

    if (
      cleaned.title &&
      cleaned.description &&
      cleaned.dueDate &&
      ["OPEN", "IN_PROGRESS", "DONE", "BLOCKED"].includes(cleaned.status) &&
      ["LOW", "MEDIUM", "HIGH"].includes(cleaned.priority)
    ) {
      tasks.push(cleaned);
    }
  }

  output.push({
    json: {
      batchIndex: index,
      batchCount: tasks.length,
      batchError: tasks.length === 0 ? "No valid tasks parsed from this batch" : null,
      tasks
    }
  });
}

return output;

const response = $json;
const headers = response.headers || {};

const sessionId =
  headers["mcp-session-id"] ||
  headers["Mcp-Session-Id"] ||
  headers["MCP-Session-Id"];

if (!sessionId) {
  throw new Error(
    "Initialize MCP succeeded but no mcp-session-id header was returned"
  );
}

return [
  {
    json: {
      sessionId,
      initializeResponse: response.body || response
    }
  }
];
